  @protected
  void sse_encode_madar_error(MadarError self, SseSerializer serializer) {
    // Codec=Sse (Serialization based), see doc to use other codecs
    switch (self) {
      case MadarError_Offline(detail: final detail):
        sse_encode_i_32(0, serializer);
        sse_encode_String(detail, serializer);
      case MadarError_Unauthenticated(detail: final detail):
        sse_encode_i_32(1, serializer);
        sse_encode_String(detail, serializer);
      case MadarError_Forbidden(resource: final resource, action: final action):
        sse_encode_i_32(2, serializer);
        sse_encode_String(resource, serializer);
        sse_encode_String(action, serializer);
      case MadarError_Validation(field: final field, detail: final detail):
        sse_encode_i_32(3, serializer);
        sse_encode_String(field, serializer);
        sse_encode_String(detail, serializer);
      case MadarError_Server(
        status: final status,
        code: final code,
        detail: final detail,
      ):
        sse_encode_i_32(4, serializer);
        sse_encode_u_16(status, serializer);
        sse_encode_String(code, serializer);
        sse_encode_String(detail, serializer);
      case MadarError_Transient(detail: final detail):
        sse_encode_i_32(5, serializer);
        sse_encode_String(detail, serializer);
      case MadarError_Internal(detail: final detail):
        sse_encode_i_32(6, serializer);
        sse_encode_String(detail, serializer);
    }
  }

