  /// offline is reconstructed from local data.
  Future<ShiftReportView> shiftReportFor({required String shiftId}) =>
      RustBridge.instance.api.crateApiBridgeMadarBridgeShiftReportFor(
        that: this,
        shiftId: shiftId,
      );

